#include <stdio.h>

int main() {
    int t;
    scanf("%d", &t);

    while (t--) {
        int n;
        scanf("%d", &n);

        int arr[n];
        int *ptr = arr;

        for (int i = 0; i < n; i++) {
            scanf("%d", ptr + i);
        }

        for (int i = n-1; i >= 0; i--) {
            printf("%d ", *(ptr + i));
        }
        printf("\n");
    }

    return 0;
}
